// e2e/form-validation.spec.ts
import { test, expect } from './utils/test-fixtures';

test.describe('Form Validation', () => {
  test.describe('Session Form', () => {
    test.beforeEach(async ({ page }) => {
      await page.goto('/sessions/new');
    });

    test('shows error for research question under min length', async ({ page, logger }) => {
      await withStep(logger, page, 'Enter short question', async () => {
        await page.getByLabel(/research question/i).fill('Why?');
        await page.getByLabel(/research question/i).blur();
      });

      await withStep(logger, page, 'Verify validation error', async () => {
        await expect(page.getByText(/at least \d+ characters/i)).toBeVisible();
        logger.info('Min length validation displayed');
      });

      await withStep(logger, page, 'Correct the input', async () => {
        await page.getByLabel(/research question/i).fill(
          'Does role-separated prompting improve Brenner artifact quality compared to unified prompts?'
        );
      });

      await withStep(logger, page, 'Verify error cleared', async () => {
        await expect(page.getByText(/at least \d+ characters/i)).not.toBeVisible();
        logger.info('Error cleared after correction');
      });
    });

    test('prevents submission without required excerpts', async ({ page, logger }) => {
      await page.getByLabel(/research question/i).fill('Valid research question here');

      await withStep(logger, page, 'Submit without excerpts', async () => {
        await page.getByRole('button', { name: /start session/i }).click();
      });

      await withStep(logger, page, 'Verify excerpt error', async () => {
        await expect(page.getByText(/select.*excerpt/i)).toBeVisible();
      });
    });

    test('enforces maximum excerpt limit', async ({ page, logger }) => {
      await withStep(logger, page, 'Open excerpt selector', async () => {
        await page.getByRole('button', { name: /select excerpts/i }).click();
      });

      await withStep(logger, page, 'Select many excerpts', async () => {
        const excerpts = page.locator('[data-testid="excerpt-item"]');
        const count = await excerpts.count();

        // Try to select more than limit
        for (let i = 0; i < Math.min(count, 15); i++) {
          await excerpts.nth(i).click();
        }
      });

      await withStep(logger, page, 'Verify limit message', async () => {
        await expect(page.getByText(/maximum.*reached|limit/i)).toBeVisible();
        logger.info('Excerpt limit enforced');
      });
    });

    test('announces errors for screen readers', async ({ page, logger }) => {
      await page.getByRole('button', { name: /start session/i }).click();

      await withStep(logger, page, 'Check ARIA announcements', async () => {
        // Check for aria-live region or role="alert"
        const alerts = page.locator('[role="alert"], [aria-live="assertive"]');
        await expect(alerts.first()).toBeVisible();
        logger.info('Screen reader announcements present');
      });
    });
  });

  test.describe('Real-time Validation', () => {
    test('validates as user types (debounced)', async ({ page, logger }) => {
      await page.goto('/sessions/new');

      await withStep(logger, page, 'Type slowly', async () => {
        const input = page.getByLabel(/research question/i);
        await input.pressSequentially('Test', { delay: 100 });
      });

      // Should not show error immediately (debounce)
      await expect(page.getByText(/at least/i)).not.toBeVisible();

      await withStep(logger, page, 'Wait for debounce', async () => {
        await page.waitForTimeout(500);
      });

      // Now error should appear
      await expect(page.getByText(/at least/i)).toBeVisible();
    });
  });
});
